import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    private static int[][] grid5x5() {
        // 5x5 matrix: row i, col j → value (i*5 + j + 1)
        int[][] m = new int[5][5];
        for (int i = 0; i < 5; i++)
            for (int j = 0; j < 5; j++)
                m[i][j] = i * 5 + j + 1;
        return m;
    }

    @Test
    void topLeftQuadrant() {
        // sumRegion(0,0,1,1) = 1+2+6+7 = 16
        assertEquals(16, new Solution(grid5x5()).sumRegion(0, 0, 1, 1));
    }

    @Test
    void centerBlock3x3() {
        // sumRegion(1,1,3,3) = 7+8+9+12+13+14+17+18+19 = 117
        assertEquals(117, new Solution(grid5x5()).sumRegion(1, 1, 3, 3));
    }

    @Test
    void entireMatrix() {
        // Sum of 1..25 = 325
        assertEquals(325, new Solution(grid5x5()).sumRegion(0, 0, 4, 4));
    }

    @Test
    void bottomRightQuadrant() {
        // sumRegion(2,2,4,4) = 13+14+15+18+19+20+23+24+25 = 171
        assertEquals(171, new Solution(grid5x5()).sumRegion(2, 2, 4, 4));
    }

    @Test
    void singleCell() {
        // sumRegion(2,3,2,3) = matrix[2][3] = 14
        assertEquals(14, new Solution(grid5x5()).sumRegion(2, 3, 2, 3));
    }

    @Test
    void multipleQueriesSameInstance() {
        // Confirms prefix array is reused across queries
        Solution sol = new Solution(grid5x5());
        assertEquals(16,  sol.sumRegion(0, 0, 1, 1));
        assertEquals(325, sol.sumRegion(0, 0, 4, 4));
        assertEquals(14,  sol.sumRegion(2, 3, 2, 3));
    }

    @Test
    void singleRowQuery() {
        // sumRegion(2,0,2,4) = row 2 = 11+12+13+14+15 = 65
        assertEquals(65, new Solution(grid5x5()).sumRegion(2, 0, 2, 4));
    }
}
